class Solution {
public:
    string reformatNumber(string number) {
        string digits;
        for (char c : number) {
            if (isdigit(c)) digits += c;
        }
        string res;
        int n = digits.size();
        int i = 0;
        while (n > 4) {
            res += digits.substr(i, 3) + "-";
            i += 3;
            n -= 3;
        }
        if (n == 4) {
            res += digits.substr(i, 2) + "-" + digits.substr(i + 2, 2);
        } else if (n == 3) {
            res += digits.substr(i, 3);
        } else {
            res += digits.substr(i, 2);
        }
        return res;
    }
};
